using SkiaSharp;
using SkiaSharp.Views.Android;

namespace Repro;

[Activity(Label = "SKGLSurfaceView Repro", MainLauncher = true, LaunchMode = Android.Content.PM.LaunchMode.SingleTop)]
public class MainActivity : Activity
{
    private SKGLSurfaceView? _skglView;
    private int _frameCount;

    protected override void OnCreate(Bundle? savedInstanceState)
    {
        base.OnCreate(savedInstanceState);
        SetContentView(Resource.Layout.activity_main);
        _skglView = FindViewById<SKGLSurfaceView>(Resource.Id.skglSurfaceView);
        if (_skglView != null)
        {
            _skglView.PreserveEGLContextOnPause = false;
            _skglView.PaintSurface += OnPaintSurface;
        }
    }

    private void OnPaintSurface(object? sender, SKPaintGLSurfaceEventArgs e)
    {
        _frameCount++;
        var canvas = e.Surface.Canvas;
        canvas.Clear(SKColors.CornflowerBlue);
        using var paint = new SKPaint { Color = SKColors.White, TextSize = 48, IsAntialias = true };
        canvas.DrawText($"Frame: {_frameCount}", 50, 100, paint);
        if (_frameCount % 60 == 0)
            Android.Util.Log.Info("REPRO", $"Rendered frame {_frameCount}");
    }

    protected override void OnResume()
    {
        base.OnResume();
        _skglView?.OnResume();
    }

    protected override void OnPause()
    {
        _skglView?.OnPause();
        base.OnPause();
    }
}
